def rectangle_union_area(rects):
    """rects: list of (x1, y1, x2, y2). Returns total area covered."""
    events = []
    for x1, y1, x2, y2 in rects:
        events.append((x1, 1, y1, y2))  # 1 = start
        events.append((x2, -1, y1, y2)) # -1 = end
    events.sort()

    active = []  # list of (y1, y2) for active rectangles
    prev_x = events[0][0]
    total = 0

    def active_y_length():
        if not active:
            return 0
        active.sort()
        length = 0
        cur_start, cur_end = active[0]
        for s, e in active[1:]:
            if s <= cur_end:
                cur_end = max(cur_end, e)
            else:
                length += cur_end - cur_start
                cur_start, cur_end = s, e
        length += cur_end - cur_start
        return length

    for x, typ, y1, y2 in events:
        total += (x - prev_x) * active_y_length()
        if typ == 1:
            active.append((y1, y2))
        else:
            active.remove((y1, y2))
        prev_x = x

    return total

long long rectangleUnionArea(vector<vector<int>>& rects) {
    vector<tuple<int,int,int,int>> events;
    for (auto& r : rects) {
        events.push_back({r[0], 1, r[1], r[3]});
        events.push_back({r[2], -1, r[1], r[3]});
    }
    sort(events.begin(), events.end());
    vector<pair<int,int>> active;
    int prevX = get<0>(events[0]);
    long long total = 0;
    auto activeYLength = [&]() -> long long {
        if (active.empty()) return 0;
        sort(active.begin(), active.end());
        long long len = 0;
        int curStart = active[0].first, curEnd = active[0].second;
        for (auto& [s, e] : active) {
            if (s <= curEnd) curEnd = max(curEnd, e);
            else { len += curEnd - curStart; curStart = s; curEnd = e; }
        }
        len += curEnd - curStart;
        return len;
    };
    for (auto& [x, typ, y1, y2] : events) {
        total += (x - prevX) * activeYLength();
        if (typ == 1) active.push_back({y1, y2});
        else active.erase(find(active.begin(), active.end(), make_pair(y1, y2)));
        prevX = x;
    }
    return total;
}

public static long rectangleUnionArea(int[][] rects) {
