static long activeYLength(List<int[]> active) {
    if (active.isEmpty()) return 0;
    active.sort((a,b) -> a[0] - b[0]);
    long len = 0;
    int curStart = active.get(0)[0], curEnd = active.get(0)[1];
    for (int[] a : active) {
        if (a[0] <= curEnd) curEnd = Math.max(curEnd, a[1]);
        else { len += curEnd - curStart; curStart = a[0]; curEnd = a[1]; }
    }
    return len + curEnd - curStart;
}

