def regionsBySlashes(self, grid):
    n = len(grid)
    upscaled = [[0] * (3 * n) for _ in range(3 * n)]

    for r in range(n):
        for c in range(n):
            if grid[r][c] == '/':
                upscaled[r*3][c*3+2] = 1
                upscaled[r*3+1][c*3+1] = 1
                upscaled[r*3+2][c*3] = 1
            elif grid[r][c] == '\\\\':
                upscaled[r*3][c*3] = 1
                upscaled[r*3+1][c*3+1] = 1
                upscaled[r*3+2][c*3+2] = 1

    def dfs(r, c):
        if r < 0 or r >= 3*n or c < 0 or c >= 3*n or upscaled[r][c] != 0:
            return
        upscaled[r][c] = 1
        dfs(r-1, c); dfs(r+1, c); dfs(r, c-1); dfs(r, c+1)

    regions = 0
    for r in range(3*n):
        for c in range(3*n):
            if upscaled[r][c] == 0:
                regions += 1
                dfs(r, c)
    return regions

class Solution {
public:
    int regionsBySlashes(vector<string>& grid) {
        int n = grid.size();
        vector<vector<int>> g(3*n, vector<int>(3*n, 0));
        for (int r = 0; r < n; r++)
            for (int c = 0; c < n; c++)
                if (grid[r][c] == '/') {
                    g[r*3][c*3+2] = 1;
                    g[r*3+1][c*3+1] = 1;
                    g[r*3+2][c*3] = 1;
                } else if (grid[r][c] == '\\\\') {
                    g[r*3][c*3] = 1;
                    g[r*3+1][c*3+1] = 1;
                    g[r*3+2][c*3+2] = 1;
                }
        int regions = 0, sz = 3*n;
        function<void(int,int)> dfs = [&](int r, int c) {
            if (r < 0 || r >= sz || c < 0 || c >= sz || g[r][c]) return;
            g[r][c] = 1;
            dfs(r-1,c); dfs(r+1,c); dfs(r,c-1); dfs(r,c+1);
        };
        for (int r = 0; r < sz; r++)
            for (int c = 0; c < sz; c++)
                if (!g[r][c]) { regions++; dfs(r, c); }
        return regions;
    }
};

class Solution {
    public int regionsBySlashes(String[] grid) {
        int n = grid.length;
        int[][] g = new int[3*n][3*n];
        for (int r = 0; r < n; r++)
            for (int c = 0; c < n; c++) {
                char ch = grid[r].charAt(c);
                if (ch == '/') {
                    g[r*3][c*3+2] = 1;
                    g[r*3+1][c*3+1] = 1;
                    g[r*3+2][c*3] = 1;
                } else if (ch == '\\\\') {
                    g[r*3][c*3] = 1;
                    g[r*3+1][c*3+1] = 1;
                    g[r*3+2][c*3+2] = 1;
                }
            }
        int sz = 3*n, regions = 0;
        for (int r = 0; r < sz; r++)
            for (int c = 0; c < sz; c++)
                if (g[r][c] == 0) { regions++; dfs(g, r, c, sz); }
        return regions;
    }
    void dfs(int[][] g, int r, int c, int sz) {
        if (r < 0 || r >= sz || c < 0 || c >= sz || g[r][c] != 0) return;
        g[r][c] = 1;
        dfs(g, r-1, c, sz); dfs(g, r+1, c, sz);
        dfs(g, r, c-1, sz); dfs(g, r, c+1, sz);
    }
}

var regionsBySlashes = function(grid) {
